func TestLicenseParsing_Errors(t *testing.T) {
	c := &config.Config{}

	c.License = &config.License{
		Name:       "TEST",
		Scoreboard: "",
	}
	c.Reporting = config.Reporting{
		Host:           "localhost:8080",
		Username:       stringPtr("test-user"),
		Password:       stringPtr("test-pass"),
		Token:          stringPtr("test-token"),
		UserAgent:      "",
		UserAgentEmail: "",
		DisableCreds:   false,
	}

	err := LicenseParse(c)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	require.Len(t, c.Licenses, 1)
	require.Contains(t, c.Licenses[0].Name, "TEST")
}

